css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; display: flex; align-items: center; justify-content: center; background: #0a0f1e; font-family: -apple-system, BlinkMacSystemFont, sans-serif; color: white; }
.game { text-align: center; }
h1 { font-size: 36px; font-weight: 900; margin-bottom: 28px; background: linear-gradient(135deg, #3b82f6, #8b5cf6); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.score-board { display: flex; gap: 20px; justify-content: center; margin-bottom: 24px; }
.score-item { width: 120px; padding: 16px; border-radius: 16px; background: rgba(255,255,255,0.05); border: 2px solid transparent; transition: border-color 0.3s; }
.score-item.active-x { border-color: #3b82f6; } .score-item.active-o { border-color: #ec4899; }
.score-symbol { font-size: 28px; font-weight: 900; margin-bottom: 4px; } .score-symbol.x { color: #3b82f6; } .score-symbol.o { color: #ec4899; } .score-symbol.d { color: #6b7280; }
.score-name { font-size: 12px; color: #6b7280; margin-bottom: 8px; } .score-num { font-size: 28px; font-weight: 800; }
.turn-indicator { font-size: 16px; font-weight: 600; color: #94a3b8; margin-bottom: 20px; }
.board { display: grid; grid-template-columns: repeat(3, 1fr); gap: 10px; width: 300px; margin: 0 auto 20px; }
.cell { width: 90px; height: 90px; border-radius: 16px; background: rgba(255,255,255,0.06); border: 2px solid rgba(255,255,255,0.08); display: flex; align-items: center; justify-content: center; font-size: 40px; font-weight: 900; cursor: pointer; transition: all 0.2s; user-select: none; } .cell:hover:empty { background: rgba(255,255,255,0.1); } .cell.x { color: #3b82f6; border-color: rgba(59,130,246,0.3); background: rgba(59,130,246,0.08); } .cell.o { color: #ec4899; border-color: rgba(236,72,153,0.3); background: rgba(236,72,153,0.08); } .cell.win { background: rgba(234,179,8,0.15); border-color: #eab308; animation: pulse 0.5s ease; }
@keyframes pulse { 0%, 100% { transform: scale(1); } 50% { transform: scale(1.08); } }
.result-msg { font-size: 20px; font-weight: 700; margin-bottom: 20px; min-height: 28px; color: #eab308; }
.reset-btn { padding: 14px 36px; border-radius: 14px; border: none; background: linear-gradient(135deg, #3b82f6, #8b5cf6); color: white; font-size: 16px; font-weight: 700; cursor: pointer; transition: opacity 0.2s; } .reset-btn:hover { opacity: 0.85; }

