let board = Array(9).fill(''), current = 'X', scores = {X:0, O:0, D:0}, gameOver = false;
const wins = [[0,1,2],[3,4,5],[6,7,8],[0,3,6],[1,4,7],[2,5,8],[0,4,8],[2,4,6]];
function play(i) {
  if (board[i] || gameOver) return;
  board[i] = current;
  const cell = document.querySelectorAll('.cell')[i];
  cell.textContent = current;
  cell.classList.add(current.toLowerCase());
  const win = checkWin();
  if (win) {
    win.forEach(i => document.querySelectorAll('.cell')[i].classList.add('win'));
    document.getElementById('result').textContent = current + ' KazandÄ±! ð';
    scores[current]++;
    updateScores(); gameOver = true;
    document.getElementById('score-x').classList.remove('active-x');
    document.getElementById('score-o').classList.remove('active-o');
  } else if (board.every(c => c)) {
    document.getElementById('result').textContent = 'Beraberlik! ð¤';
    scores.D++; updateScores(); gameOver = true;
  } else {
    current = current === 'X' ? 'O' : 'X';
    document.getElementById('turn').textContent = current + "'in SÄ±rasÄ±";
    document.getElementById('score-x').classList.toggle('active-x', current === 'X');
    document.getElementById('score-o').classList.toggle('active-o', current === 'O');
  }
}
function checkWin() { return wins.find(([a,b,c]) => board[a] && board[a] === board[b] && board[a] === board[c]) || null; }
function updateScores() { document.getElementById('score-x-num').textContent = scores.X; document.getElementById('score-o-num').textContent = scores.O; document.getElementById('score-d-num').textContent = scores.D; }
function reset() {
  board = Array(9).fill(''); current = 'X'; gameOver = false;
  document.querySelectorAll('.cell').forEach(c => { c.textContent = ''; c.className = 'cell'; });
  document.getElementById('result').textContent = '';
  document.getElementById('turn').textContent = "X'in SÄ±rasÄ±";
  document.getElementById('score-x').classList.add('active-x');
  document.getElementById('score-o').classList.remove('active-o');
}
reset();
